const e=JSON.parse('{"key":"v-4664fbe6","path":"/vue/vue%E8%A7%A3%E8%AF%BB%E6%BA%90%E7%A0%81%E4%B9%8B%E6%B8%B2%E6%9F%93%E6%9B%B4%E6%96%B0.html","title":"vue解读源码之渲染更新","lang":"zh-CN","frontmatter":{"title":"vue解读源码之渲染更新","isTimeLine":true,"date":"2025-09-28T00:00:00.000Z","category":["前端"],"tag":["Vue","源码"]},"headers":[{"level":3,"title":"渲染更新","slug":"渲染更新","link":"#渲染更新","children":[]},{"level":3,"title":"渲染 Watcher","slug":"渲染-watcher","link":"#渲染-watcher","children":[]},{"level":3,"title":"定义Dep","slug":"定义dep","link":"#定义dep","children":[]},{"level":3,"title":"对象的依赖收集","slug":"对象的依赖收集","link":"#对象的依赖收集","children":[]}],"git":{"createdTime":1773506313000,"updatedTime":1773506313000,"contributors":[{"name":"liunal","email":"liunal","commits":1}]},"readingTime":{"minutes":4.51,"words":1354},"filePathRelative":"vue/vue解读源码之渲染更新.md","localizedDate":"2025年9月28日","excerpt":"<h3> 渲染更新</h3>\\n<ol>\\n<li>为了解决当我们改变数据的时候发现页面并不会自动更新</li>\\n<li>vue采用观察者模式定义Watcher和Dep完成依赖收集和派发更新,从而实现渲染更新</li>\\n</ol>\\n<h4> 定义Watcher</h4>\\n<ol>\\n<li>观察者：<code>update()、addDep()</code>订阅数据的变动，当数据变动时通知它去渲染视图</li>\\n<li>src/observer/watcher.js</li>\\n<li>class Watcher{}</li>\\n</ol>\\n<h3> 渲染 Watcher</h3>\\n<ol>\\n<li><code>mountComponent(){new Watcher(vm, updateComponent, null, true);}</code></li>\\n<li>注册一个渲染watcher,执行<code>vm._update(vm._render())</code>方法渲染视图</li>\\n</ol>"}');export{e as data};
